  UNIQUE KEY `uk_page_type` (`tenant_id`,`page_type`,`shop_id`,`client_type`),
  KEY `ids_tenant_id` (`tenant_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='页面设计表';

